import sys

class Solution:
    def convertPrefixToPostfix(self, prefix: str) -> str:
        stack = []
        operators = {'+', '-', '*', '/', '^'}
        for c in reversed(prefix):
            if c in operators:
                if len(stack) >= 2:
                    op1 = stack.pop()
                    op2 = stack.pop()
                    temp = op1 + op2 + c
                    stack.append(temp)
            else:
                stack.append(c)
        return stack[0] if stack else ""

