#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    bool isOperator(char c) {
        return c == '+' || c == '-' || c == '*' || c == '/' || c == '^';
    }

public:
    string convertPrefixToPostfix(string prefix) {
        stack<string> s;
        for (int i = prefix.length() - 1; i >= 0; i--) {
            char c = prefix[i];
            if (isOperator(c)) {
                if (s.size() < 2) continue;
                string op1 = s.top(); s.pop();
                string op2 = s.top(); s.pop();
                string temp = op1 + op2 + c;
                s.push(temp);
            } else {
                s.push(string(1, c));
            }
        }
        return s.empty() ? "" : s.top();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string prefix;
    if (!(cin >> prefix)) return 0;
    Solution sol;
    cout << sol.convertPrefixToPostfix(prefix) << "\n";
    return 0;
}
